def balanced(s):
    count = 0
    for char in s:
        if char == '(':
            count += 1
        elif char == ')':
            count -= 1
        # If count goes negative, there's a closing parenthesis before its opening partner
        if count < 0:
            return False
    # If count is zero, all parentheses are balanced
    return count == 0

# Edge case: An empty string is considered balanced.
assert balanced('') == True
